#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
const int N=4010;int n,QAQ,p[N];vector<int> d[N];
inline void Solve(int mid)
{
	rep(1,n/2+3,dt)
	{
		if(mid+dt<=n)d[mid].push_back(mid+dt);else break;
		if(mid-dt>=1)d[mid].push_back(mid-dt);else break;
	}
}
int main()
{
	scanf("%d%d",&n,&QAQ);QAQ=0;
	int mid=(1+n)>>1;
	rep(1,n,i)d[i].push_back(i);Solve(mid);
	rep(1,n/2+3,dt)
	{
		if(mid+dt<=n)Solve(mid+dt);
		if(mid-dt>=1)Solve(mid-dt);
	}
	rep(1,n,i)p[i]=i;
	sort(p+1,p+n+1,[&](int x,int y){return d[x].size()<d[y].size();});
	rep(1,n,i){for(int v:d[p[i]])printf("%d ",v);putchar('\n');}
	return QAQ;
}
